def process_payment_transaction(transaction_data):
    # Business logic for payment transactions
    amount = transaction_data.get('amount', 0)
    account_id = transaction_data.get('account_id')
    transaction_id = transaction_data.get('transaction_id')
    
    # Example processing logic
    if amount > 10000:
        print(f"High value transaction detected: {transaction_id}")
    
    print(f"Processing payment: {transaction_id} for {amount} to account {account_id}")

def process_refund_transaction(transaction_data):
    # Business logic for refund transactions
    original_transaction_id = transaction_data.get('original_transaction_id')
    refund_amount = transaction_data.get('amount', 0)
    
    print(f"Processing refund: {original_transaction_id} for {refund_amount}")

